+{"id":"bd-1if","title":"Port --robot-graph parity (json/dot/mermaid + filters + explanations)","description":"Implement --robot-graph in bvr with graph-format, graph-root, graph-depth, label filter, deterministic output, and parity-focused tests using legacy behavior.","status":"closed","priority":0,"issue_type":"feature","assignee":"ubuntu","created_at":"2026-02-17T23:42:06.747943951Z","created_by":"ubuntu","updated_at":"2026-02-17T23:51:55.259182713Z","closed_at":"2026-02-17T23:51:55.259164428Z","close_reason":"Completed robot-graph parity implementation","source_repo":".","compaction_level":0,"original_size":0,"labels":["graph","parity","porting","robot"]}
