+{"id":"bd-1pw","title":"Port --robot-diff metadata parity","description":"Implement full legacy-style --robot-diff payload parity, including from/to timestamps, revision metadata, cycle deltas, metric deltas, removed/new cycle sets, and expanded summary fields; add fixture-driven conformance assertions.","status":"closed","priority":0,"issue_type":"feature","created_at":"2026-02-18T02:43:15.492279271Z","created_by":"ubuntu","updated_at":"2026-02-18T02:51:52.783738995Z","closed_at":"2026-02-18T02:51:52.783716864Z","close_reason":"Implemented legacy-style robot-diff metadata payload parity and expanded conformance assertions","source_repo":".","compaction_level":0,"original_size":0,"labels":["diff","parity","porting","robot"]}
