+{"id":"bd-2s3","title":"Port --robot-suggest parity (duplicate/dependency/label/cycle)","description":"Implement --robot-suggest with suggest-type/suggest-confidence/suggest-bead filters and parity tests.","status":"closed","priority":1,"issue_type":"feature","assignee":"ubuntu","created_at":"2026-02-17T23:42:14.484957588Z","created_by":"ubuntu","updated_at":"2026-02-18T01:25:17.372773773Z","closed_at":"2026-02-18T01:25:17.372752594Z","close_reason":"Implemented --robot-suggest parity surface with filters and conformance tests","source_repo":".","compaction_level":0,"original_size":0,"labels":["parity","porting","robot","suggest"],"dependencies":[{"issue_id":"bd-2s3","depends_on_id":"bd-1if","type":"blocks","created_at":"2026-03-05T00:07:49Z","created_by":"import","metadata":"{}","thread_id":""}]}
