+    fn handle_pages_wizard_key(&mut self, code: KeyCode, mut wiz: PagesWizardState) -> Cmd<Msg> {
+        match code {
+            KeyCode::Escape => {
+                self.modal_overlay = None;
+                return Cmd::None;
